/**
 * @param list<string> $items
 * @return list<array{title: string, items: list<string>}>
 */
function esh_changelog_group_items(array $items): array
{
    $titles = [
        'Kurulum, migrasyon ve şema (başlangıç)',
        'Hasta kartı, düzenleme ve planlı izlem',
        'Hasta kartı detayı, istatistik bağlantıları ve EK-3',
        'İlaç/tanı raporu (`HastaIlacRapor`) ve veritabanı',
        'e-Rapor, WinUI stilleri ve admin şablonları',
        'WinUI tamamlama ve tema manifest / `templates` taşınması',
        'Tema sistemi fazları ve yönetim arayüzü',
        'İstatistik merkezi, dashboard yönetim ve kullanıcı',
        'Hasta akışları, adres, izlem formları ve rol',
        'Dashboard takvimi, nöbet ve vefat süreçleri',
        'Listeler, e-Rapor, refaktör ve `migration.php` altyapısı',
        'Migrasyon işçisi, adres senkronu ve dashboard ince ayarları',
    ];
    $chunks = array_chunk($items, 20);
    $out = [];
    foreach ($chunks as $i => $chunk) {
        $out[] = [
            'title' => $titles[$i] ?? ('Kayıtlar ' . ($i + 1)),
            'items' => $chunk,
        ];
    }

    return $out;
}

