<script>
(function () {
    function rootEl(id) {
        return document.getElementById(id);
    }
    document.querySelectorAll('.esh-changelog-expand-all').forEach(function (btn) {
        btn.addEventListener('click', function () {
            var id = btn.getAttribute('data-esh-collapse-root');
            var root = id ? rootEl(id) : null;
            if (!root) return;
            root.querySelectorAll('.collapse').forEach(function (el) {
                window.bootstrap.Collapse.getOrCreateInstance(el, { toggle: false }).show();
            });
            root.querySelectorAll('[data-bs-toggle="collapse"]').forEach(function (t) {
                t.classList.remove('collapsed');
                t.setAttribute('aria-expanded', 'true');
            });
        });
    });
    document.querySelectorAll('.esh-changelog-collapse-all').forEach(function (btn) {
        btn.addEventListener('click', function () {
            var id = btn.getAttribute('data-esh-collapse-root');
            var root = id ? rootEl(id) : null;
            if (!root) return;
            root.querySelectorAll('.collapse').forEach(function (el) {
                var c = window.bootstrap.Collapse.getInstance(el);
                if (c) c.hide();
            });
            root.querySelectorAll('[data-bs-toggle="collapse"]').forEach(function (t) {
                t.classList.add('collapsed');
                t.setAttribute('aria-expanded', 'false');
            });
        });
    });
})();
</script>
